class SegmentTreeMax {
    constructor(n) {
        this.n = n;
        this.size = n;
        this.tree = Array(4 * n).fill(-Infinity);
    }

    update(pos, value, node = 0, l = 0, r = this.size - 1) {
        if (l === r) {
            this.tree[node] = value;
            return;
        }
        let mid = Math.floor((l + r) / 2);
        if (pos <= mid) {
            this.update(pos, value, 2 * node + 1, l, mid);
        } else {
            this.update(pos, value, 2 * node + 2, mid + 1, r);
        }
        this.tree[node] = Math.max(this.tree[2 * node + 1], this.tree[2 * node + 2]);
    }

    query(qleft, qright, node = 0, l = 0, r = this.size - 1) {
        if (qleft > r || qright < l) return -Infinity;
        if (qleft <= l && r <= qright) {
            return this.tree[node];
        }
        let mid = Math.floor((l + r) / 2);
        let leftRes = this.query(qleft, qright, 2 * node + 1, l, mid);
        let rightRes = this.query(qleft, qright, 2 * node + 2, mid + 1, r);
        return Math.max(leftRes, rightRes);
    }
}

