function solve(s, order, k) {
    const n = s.length;
    const totalSub = Math.floor(n * (n + 1) / 2);
    const size = n + 2;

    const treeMax = new SegmentTreeMax(size);
    const treeMin = new SegmentTreeMin(size);

    treeMax.update(0, -1);
    treeMin.update(0, -1);
    treeMax.update(n + 1, n);
    treeMin.update(n + 1, n);

    let invalidCount = totalSub;

    for (let t = 0; t < n; t++) {
        const p = order[t];
        const leftBreak = treeMax.query(0, p);
        const rightBreak = treeMin.query(p + 2, size - 1);

        const L_total = rightBreak - leftBreak - 1;
        const L1 = p - leftBreak - 1;
        const L2 = rightBreak - p - 1;

        const old_segment_count = L_total * (L_total + 1) / 2;
        const new_segment_count = (L1 * (L1 + 1) / 2) + (L2 * (L2 + 1) / 2);

        invalidCount = invalidCount - old_segment_count + new_segment_count;
        const validCount = totalSub - invalidCount;

        if (validCount >= k) {
            return t;
        }

        treeMax.update(p + 1, p);
        treeMin.update(p + 1, p);
    }

    return -1;
}
