class SegmentTreeMax {
    constructor(size) {
        this.n = size;
        this.tree = new Array(4 * size).fill(-Infinity);
    }

    update(idx, value, node = 1, segL = 0, segR = this.n - 1) {
        if (segL === segR) {
            this.tree[node] = value;
            return;
        }
        const mid = Math.floor((segL + segR) / 2);
        if (idx <= mid) {
            this.update(idx, value, node * 2, segL, mid);
        } else {
            this.update(idx, value, node * 2 + 1, mid + 1, segR);
        }
        this.tree[node] = Math.max(this.tree[node * 2], this.tree[node * 2 + 1]);
    }

    query(l, r, node = 1, segL = 0, segR = this.n - 1) {
        if (l > r) return -Infinity;
        if (l <= segL && segR <= r) {
            return this.tree[node];
        }
        const mid = Math.floor((segL + segR) / 2);
        let leftRes = -Infinity;
        let rightRes = -Infinity;
        if (l <= mid) {
            leftRes = this.query(l, Math.min(mid, r), node * 2, segL, mid);
        }
        if (r > mid) {
            rightRes = this.query(Math.max(mid + 1, l), r, node * 2 + 1, mid + 1, segR);
        }
        return Math.max(leftRes, rightRes);
    }
}

