function solve(s, order, k) {
    const n = s.length;
    const total_substrings = Math.floor(n * (n + 1) / 2);
    if (k > total_substrings) {
        return -1;
    }

    let total_invalid = total_substrings;
    const segTreeMax = new SegmentTreeMax(n);
    const segTreeMin = new SegmentTreeMin(n);

    for (let t = 0; t < n; t++) {
        const p = order[t];

        let leftNeighbor = -Infinity;
