            leftNeighbor = segTreeMax.query(0, p - 1);
        }
        if (leftNeighbor === -Infinity) {
            leftNeighbor = -1;
        }

        let rightNeighbor = Infinity;
        if (p < n - 1) {
            rightNeighbor = segTreeMin.query(p + 1, n - 1);
        }
        if (rightNeighbor === Infinity) {
            rightNeighbor = -1;
        }

        const L_bound = leftNeighbor === -1 ? 0 : leftNeighbor + 1;
        const R_bound = rightNeighbor === -1 ? n - 1 : rightNeighbor - 1;

        const gap_len = R_bound - L_bound + 1;
        const current_tri = Math.floor(gap_len * (gap_len + 1) / 2);

        const len1 = p - L_bound;
        const len2 = R_bound - p;

        let new_tri = 0;
        if (len1 > 0) {
            new_tri += Math.floor(len1 * (len1 + 1) / 2);
        }
